INSERT INTO knowledge_rule (type, category, title, keywords, rule_content, example, priority, enabled, create_time, update_time)
VALUES
('ZIWEI','综合命盘','紫微分析先定命身再定三方四正','综合 命盘 命宫 身宫 三方四正 命主 身主 五行局','紫微斗数断命盘不可只看单宫。先看命宫、身宫、命主、身主、五行局，定性格底色与承接能力；再看命宫三方四正，即命宫、财帛、官禄、迁移四宫，判断事业、财运、外部机会和人生主轴。辅星、小星、长生十二神只作辅助，不可压过主星、四化和宫位结构。','命宫吉而三方四正弱，不能直接断一生顺遂；需看财官迁移是否能承接。',100,1,NOW(),NOW()),
('ZIWEI','典籍-紫微斗数全书','诸星入宫要分庙旺陷与宫位主题','紫微斗数全书 主星 庙旺 落陷 宫位 十二宫','《紫微斗数全书》重视星曜入十二宫的宫位主题。判断主星时，先看星曜本性，再看庙旺平陷和落入何宫。庙旺多能发挥正面能力，落陷则容易表现为辛苦、偏性或不稳定；但仍需结合三方四正和四化，不可只凭单星定吉凶。','太阳化忌落福德，不能只断凶，还要看命宫和官禄是否有吉曜承接。',98,1,NOW(),NOW()),
('ZIWEI','典籍-紫微斗数全书','十二宫各有所主不可混断','十二宫 命宫 兄弟 夫妻 子女 财帛 疾厄 迁移 交友 官禄 田宅 福德 父母','十二宫各有现实落点：命宫看自身性格与人生主轴，兄弟看同辈与协作，夫妻看伴侣与亲密关系，子女看子女、作品与创造，财帛看收入资源，疾厄看身体与压力，迁移看外部环境，交友看朋友下属，官禄看事业平台，田宅看居住资产，福德看精神享受，父母看长辈文书。断事必须落回用户所问宫位。','问事业时以官禄为核心，联动命、财、迁；不宜把夫妻宫信息当事业主轴。',96,1,NOW(),NOW()),
('ZIWEI','命身','命宫看先天底色身宫看后天着力点','命宫 身宫 命身 性格 人生重心','命宫偏先天性格、思维方式、人生底色；身宫偏后天着力点、行动重心和人生较执着的领域。身宫落哪一宫，该宫主题往往在人生中被反复强化。命身同宫则自我意识强，命身分宫则常有内外两套关注点。','身宫在夫妻宫，感情、伴侣关系和合作关系会成为长期课题。',95,1,NOW(),NOW()),
('ZIWEI','三方四正','命财官迁组成主要格局骨架','三方四正 命宫 财帛 官禄 迁移 格局','命宫、财帛、官禄、迁移为命盘三方四正，是判断整体格局的骨架。命宫定人，财帛定资源和赚钱方式，官禄定事业路径，迁移定外部机会和环境变化。四宫同看，才能判断一个人靠什么成事、在哪里受阻、适合守成还是外出发展。','命宫天梁、官禄天机、财帛太阴，可先按智慧服务型、稳定策划型路径解读。',95,1,NOW(),NOW()),
('ZIWEI','四化','四化是事件变化和应期的重要触发','四化 化禄 化权 化科 化忌 甲年 廉贞 破军 武曲 太阳','四化代表星曜在命盘中的动态变化。化禄主资源、机会、人缘与欲望；化权主掌控、压力、竞争与执行；化科主名誉、文书、考试和缓和；化忌主执念、阻滞、亏欠和反复。断事时要看四化落在哪一宫、冲照哪一宫，以及是否引动用户所问主题。','甲年生人廉贞化禄、破军化权、武曲化科、太阳化忌，需看这些星分别落宫。',94,1,NOW(),NOW()),
('ZIWEI','四化','化禄不等于全吉化忌不等于全凶','化禄 化忌 吉凶 转化 执念','化禄多带来资源和吸引力，但也可能带来欲望、享乐和过度投入；化忌多代表卡点、亏欠和执念，但也指出最需要修正的地方。判断吉凶要看宫位、星性、三方四正和现实问题，不能见禄就喜、见忌就恐吓。','子女宫廉贞化禄可主创意桃花旺，但若同宫煞曜重，也要防情感放纵和消费。',93,1,NOW(),NOW()),
('ZIWEI','典籍-斗数骨髓赋','骨髓赋重格局组合不重孤星','斗数骨髓赋 格局 组合 三方四正 吉凶轻重','《斗数骨髓赋》重在格局和星曜组合，强调星曜之间互相成就或互相破坏。断盘时应先看成格条件：主星是否得地，三方是否会吉，煞忌是否冲破，四化是否有情。孤立摘一句星曜断语容易失真。','见紫微破军，不可直接断大富大贵；要看左右昌曲魁钺和煞忌是否配合。',92,1,NOW(),NOW()),
('ZIWEI','典籍-斗数骨髓赋','吉曜成群能增光煞曜冲破要降级','六吉 六煞 左辅 右弼 文昌 文曲 天魁 天钺 擎羊 陀罗 火星 铃星 地空 地劫','六吉曜会照，常主助力、贵人、文书、名誉和缓冲；六煞曜会照，常主竞争、冲突、破耗、波动和压力。吉曜成群能提高格局层次，煞曜冲破则需降低判断等级。煞曜并非一定坏，得制或用于竞争行业也可转为行动力。','官禄见天机右弼，利策划助力；若再会火铃空劫，则事业变动和压力增大。',91,1,NOW(),NOW()),
('ZIWEI','典籍-增补太微赋','太微赋重宫星互参和吉凶轻重','增补太微赋 太微赋 宫星互参 吉凶轻重','《太微赋》一路重视宫位与星曜互参，同一星在不同宫位取象不同，同一宫位遇不同星曜吉凶也不同。判断时要把星性、宫位、人事主题、四化和对宫共同解释，并说明吉凶轻重，不宜绝对化。','巨门在夫妻宫偏沟通争执，在官禄宫可作口才、法律、咨询。',90,1,NOW(),NOW()),
('ZIWEI','典籍-十喻歌','十喻歌重本对合邻和全局权衡','十喻歌 本宫 对宫 合宫 邻宫 三方四正','《十喻歌》可用来提醒断盘要看本宫、对宫、三合宫和邻宫气势。本宫是直接状态，对宫是外来牵动，三合宫是结构支援，邻宫可看夹辅夹制。综合权衡后再下结论，避免单点判断。','夫妻宫巨门不只看伴侣，还要看对宫官禄和三方福德迁移的支援。',90,1,NOW(),NOW()),
('ZIWEI','星曜-紫微','紫微主统御格局但怕孤君无辅','紫微 主星 帝星 领导 管理 孤君','紫微为帝星，主统御、格局、管理、尊贵和自我要求。紫微得辅弼昌曲魁钺会照，多能发挥领导与整合力；若孤立无辅或被煞忌冲破，容易变成压力、孤高、虚名或难落地。','紫微入交友宫，可看朋友、团队或下属中有主导型人物，也代表人际圈层要求高。',88,1,NOW(),NOW()),
('ZIWEI','星曜-天机','天机主变化谋略技术策划','天机 变化 策划 技术 谋略 官禄 事业','天机主思考、变化、谋略、技术、策划和机动性。入官禄宫多适合咨询、策划、技术、研究、教育、运营等动脑且变化多的工作。天机逢吉有巧思，逢煞忌则易多变、焦虑、计划反复。','官禄天机加右弼，利靠方案、方法和辅助资源成事。',88,1,NOW(),NOW()),
('ZIWEI','星曜-太阳','太阳主外显付出名望男亲','太阳 化忌 福德 父亲 男性 名望 付出','太阳主光明、外显、名望、男性长辈、责任和付出。太阳庙旺多主动、坦荡、有照拂力；落陷或化忌时，容易出现付出感重、心里失落、男亲缘薄、睡眠或情绪压力。具体应到所在宫位主题。','太阳化忌在福德宫，常表现为内心压力、想得多、快乐感不足。',87,1,NOW(),NOW()),
('ZIWEI','星曜-武曲','武曲主财务执行规则和刚性','武曲 财务 执行 管理 化科 父母 文书','武曲主财务、执行、制度、管理、刚性和结果。武曲化科可增正规评价、名誉、证书和文书助力；但武曲逢煞也可能显得强硬、压力大或关系冷。断财务和职业时要重视武曲所落宫位。','武曲化科在父母宫，可看长辈、文书、单位制度或资质名誉方面有助。',86,1,NOW(),NOW()),
('ZIWEI','星曜-天同天梁','天同天梁主温和福荫服务但易内软','天同 天梁 命宫 温和 福荫 服务 孤独','天同主温和、福气、享受和人缘，天梁主荫庇、原则、长辈、保护和清高。天同天梁同宫，常见善良、有服务精神、重道义，但也容易心软、想太多或有孤独感。若会吉曜，适合教育、咨询、服务、公益、文化等路线。','命宫天同天梁，可写成外表随和、内心有原则，适合稳定助人型路径。',88,1,NOW(),NOW()),
('ZIWEI','星曜-巨门','巨门主口舌沟通暗耗和是非','巨门 夫妻 口舌 沟通 是非 暗曜','巨门为暗曜，主语言、沟通、怀疑、争辩、口舌和隐性压力。落在夫妻宫时，感情重点在沟通方式，易因误会、冷战、挑剔或话语伤人产生摩擦。若会吉曜可成口才与专业表达，若逢煞忌则口舌更重。','夫妻宫巨门，核心建议是晚婚、慢磨合、明确沟通规则。',88,1,NOW(),NOW()),
('ZIWEI','星曜-太阴','太阴主财库情绪女性和细水长流','太阴 财帛 财运 女性 情绪 存钱','太阴主财富积累、女性缘、细腻、内在安全感和夜间之象。太阴入财帛，多重视稳定收入、储蓄和长期资产；庙旺则财库较足，落陷则财来得慢、心里不安或现金流反复。','财帛宫太阴落陷，适合细水长流积累，不宜激进投机。',87,1,NOW(),NOW()),
('ZIWEI','星曜-廉贞贪狼','廉贞贪狼主欲望才艺桃花和变化','廉贞 贪狼 化禄 桃花 才艺 欲望 子女','廉贞主规则、感情纠葛、审美和界限，贪狼主欲望、才艺、人缘、娱乐和变化。廉贞贪狼同宫或化禄时，人缘、创意和吸引力增强，但也要防感情复杂、享乐过度、消费冲动或边界不清。','子女宫廉贞贪狼化禄，可看作品创意、桃花娱乐或子女缘增强，但要节制。',86,1,NOW(),NOW()),
('ZIWEI','星曜-破军','破军主破旧立新和大幅变动','破军 化权 变动 破旧立新 交友 团队','破军主破旧立新、变动、开创、拆解和不稳定。破军化权则行动力、掌控欲和变革力量增强，但也容易带来冲突、换圈、团队重组或关系决裂。适合改革型事务，不适合求稳时过度冒进。','交友宫破军化权，朋友团队中强势变化多，合作要有规则。',85,1,NOW(),NOW()),
('ZIWEI','宫位-夫妻','夫妻宫看关系模式不只看结婚早晚','夫妻 感情 婚姻 伴侣 口舌 身宫','夫妻宫看亲密关系模式、伴侣性格、沟通方式和婚姻承接力，不只看结婚早晚。需联动命宫、福德、迁移和四化。身宫落夫妻，代表命主格外重视关系，关系波动对人生选择影响更大。','夫妻宫巨门加身宫，感情容易成为人生主课题，宜晚婚和重沟通。',85,1,NOW(),NOW()),
('ZIWEI','宫位-官禄','官禄宫看职业路径平台和成事方式','官禄 事业 工作 职业 平台 天机','官禄宫主职业路径、工作平台、职责名分和成事方式。判断事业要联动命宫承接力、财帛收益、迁移外部机会。官禄星曜偏动，职业多变化；偏稳，适合长期平台；吉辅多，贵人和资源多；煞忌多，压力和变动多。','官禄天机，事业宜动脑、方案、技术、咨询，不宜完全重复机械。',85,1,NOW(),NOW()),
('ZIWEI','宫位-财帛','财帛宫看赚钱方式和资源承接','财帛 财运 收入 资源 太阴 投资','财帛宫看收入方式、理财习惯、资源承接和财富安全感。财帛好不等于暴富，需看命宫能否承接、官禄能否产出、田宅能否沉淀。逢空劫煞忌时，投资、借贷和现金流要保守。','财帛太阴适合存钱和长期积累，见陷地则先求稳定现金流。',84,1,NOW(),NOW()),
('ZIWEI','宫位-田宅','田宅宫看居住房产和资产沉淀','田宅 房产 居住 火星 地空 地劫 投资','田宅宫主居住环境、房产、家庭空间和资产沉淀。田宅见火星、地空、地劫，常提示房产或居住有变动、破耗、空置、预期落空或投资风险。若问买房置业，要结合现实现金流，不可只凭命盘建议冒进。','田宅火星地空，房产投资宜谨慎，先看合同和资金安全。',84,1,NOW(),NOW()),
('ZIWEI','宫位-福德','福德宫看精神状态快乐感和内耗','福德 精神 情绪 内耗 太阳化忌 快乐感','福德宫主内心世界、快乐感、精神享受、睡眠和长期心态。福德不佳时，即使外部条件不错，也容易感到空、累、焦虑或不满足。福德见化忌，报告应给出情绪管理和生活方式建议。','福德太阳化忌，可提示减少内耗、规律作息、培养稳定兴趣。',84,1,NOW(),NOW()),
('ZIWEI','宫位-疾厄','疾厄宫只能提示偏性不可替代医学','疾厄 健康 压力 天府 陀罗 胃肠 医学边界','疾厄宫用于提示身体偏性、压力来源和需要留意的生活习惯，不能替代医学诊断。星曜和煞曜只表示风险倾向，报告中应建议体检、作息和就医，而不是断具体疾病或恐吓用户。','疾厄天府陀罗，可提示慢性消化、代谢或压力型问题，需以体检为准。',83,1,NOW(),NOW()),
('ZIWEI','大限流年','大限定阶段流年定触发','大限 流年 时间窗口 应期 阶段','紫微断时间先看大限，大限代表十年阶段主题；再看流年四化、流年宫位和原局被引动的宫位。没有明确流年资料时，只能说阶段倾向，不宜硬造具体年份。时间窗口应写成“某年龄段更明显”，并说明依据。','22-31岁走夫妻宫大限，则婚恋、人际合作和关系磨合成为阶段主题。',83,1,NOW(),NOW()),
('ZIWEI','大限流年','大限宫位主题会放大原局问题','大限 宫位 夫妻 财帛 子女 疾厄','大限走到某宫，该宫主题会被放大。走夫妻大限，关系和合作变重要；走财帛大限，收入和资源变重要；走官禄大限，事业平台变重要；走疾厄大限，身体压力和生活习惯变重要。吉凶仍看该宫星曜、四化、三方四正。','32-41岁走子女宫廉贞贪狼化禄，创意、子女、桃花和享乐主题增强。',82,1,NOW(),NOW()),
('ZIWEI','事业专题','机月同梁适合稳定智慧服务型路径','机月同梁 事业 天机 太阴 天同 天梁 公职 策划 咨询','命、财、官、迁见天机、太阴、天同、天梁形成机月同梁气象时，多适合稳定、智慧、服务、文职、教育、咨询、策划、行政、公职或专业辅助路线。若煞忌重，则压力和变动增加，但仍宜靠专业和制度成事。','命宫天同天梁、官禄天机、财帛太阴，可按机月同梁类路径解读。',82,1,NOW(),NOW()),
('ZIWEI','财运专题','太阴财帛重储蓄不重投机','太阴 财帛 财运 储蓄 投资 房产','太阴守财帛，财运多靠稳定收入、细心管理和长期储蓄。若太阴落陷或被煞忌冲破，不宜高杠杆、高波动投资；若大限流年引动财帛且会吉，适合逐步积累资产。','财帛太阴加田宅空劫时，买房和投资要放慢，重合同与现金流。',81,1,NOW(),NOW()),
('ZIWEI','感情专题','巨门夫妻重沟通规则和晚婚倾向','巨门 夫妻 感情 晚婚 沟通 争吵','夫妻宫巨门常见沟通成本高，容易互相试探、误解、争辩或心里有话不说。若身宫同落夫妻，关系影响更深。建议强调晚婚、慢磨合、明确沟通边界和选择稳定包容的对象。','问正缘或婚期时，巨门夫妻要区分有缘分和能否稳定承接。',81,1,NOW(),NOW()),
('ZIWEI','迁移专题','迁移宫看外地环境和出门机会','迁移 外地 出差 天马 禄存 发展','迁移宫看外部环境、异地发展、出差迁居、社会舞台和贵人机会。迁移见天马禄存，常有外出求财、因动得利或环境变化带来机会；但也要看命宫能否承接，避免奔波过度。','迁移天马禄存，事业建议可考虑外部平台、异地资源或流动性工作。',80,1,NOW(),NOW()),
('ZIWEI','风险边界','紫微报告要避免宿命化恐吓','边界 风险 医疗 投资 法律 宿命化','紫微斗数报告是传统术数参考，不可作绝对承诺。涉及健康、投资、法律、婚姻重大决策时，必须提醒用户结合现实证据和专业意见。表达风险要给出可行动建议，不做恐吓式断语。','健康只写风险倾向和体检建议，不断具体病名和治疗方案。',80,1,NOW(),NOW()),
('ZIWEI','输出规范','核心结论必须先给白话答案','白话 核心结论 普通用户 专业术语','紫微报告的核心结论应先用普通用户能懂的白话回答问题，说明总体走向、优势、阻力、何时更容易转好、接下来怎么做。命宫、身宫、四化、主星等专业术语放在依据和详细分析中解释，不要堆在核心结论里。','核心结论不要写“命宫天同天梁”，应写“你外柔内刚，适合稳定服务型路线”。',79,1,NOW(),NOW()),
('ZIWEI','案例-紫微','案例：天同天梁坐命的服务型人生','案例 天同 天梁 命宫 性格 事业','案例结构：命宫天同天梁，三方见天机太阴或辅曜。断法：性格温和有原则，适合教育、咨询、行政、服务、公益、文化等稳定助人路线。若福德化忌，则外表温和但内心压力重，需要减少内耗。','命宫天同天梁，报告可落到善良、有原则、适合稳定助人型职业。',78,1,NOW(),NOW()),
('ZIWEI','案例-紫微','案例：巨门在夫妻宫的感情磨合','案例 巨门 夫妻 感情 沟通 晚婚','案例结构：夫妻宫巨门，或身宫落夫妻并见巨门、旬空、华盖。断法：感情重精神沟通，容易因语言、冷战、猜疑产生摩擦。建议晚婚、慢磨合，选择包容稳定对象。','22-31岁走夫妻大限时，关系磨合和伴侣选择是重点。',78,1,NOW(),NOW()),
('ZIWEI','案例-紫微','案例：太阴财帛的慢财格局','案例 太阴 财帛 财运 储蓄','案例结构：财帛宫太阴，官禄命宫能形成稳定职业路径。断法：财运不宜追求暴富，适合稳定收入、长期储蓄、保守理财；若田宅空劫火铃重，则置业投资更需谨慎。','财帛太阴落陷时，先强调现金流和储蓄习惯。',77,1,NOW(),NOW()),
('ZIWEI','案例-紫微','案例：太阳化忌在福德的内耗问题','案例 太阳化忌 福德 内耗 情绪','案例结构：太阳化忌落福德或冲照精神宫位。断法：外部责任感强，内心容易累、焦虑、快乐感不足，男亲缘分或对男性权威的感受复杂。建议规律作息、减少自责、建立稳定兴趣。','报告中应把太阳化忌翻译成“容易想太多、付出后不满足”。',77,1,NOW(),NOW()),
('ZIWEI','案例-紫微','案例：迁移天马禄存的外出得机','案例 迁移 天马 禄存 外地 出差','案例结构：迁移宫见天马、禄存或吉曜，命宫能承接。断法：外出、异地、换环境、跨平台合作会带来机会；但若煞忌重，奔波成本和不稳定也要说明。','事业建议可写“机会不一定在原地，外部平台更容易打开”。',76,1,NOW(),NOW());
